"use client";

import { useToast, Button, Label } from "@/shared/ui";
import React, { useCallback, useEffect, useMemo, useState, useRef } from "react";
import { Download, RefreshCw, Save, ChevronRight, ChevronDown, Check } from "lucide-react";

import type { ExternalCategory, CategoryMappingWithDetails } from "@/features/integrations/types/category-mapping";
import type { ProductCategory, Catalog } from "@/features/products";

import { useCatalogs } from "@/features/products/hooks/useCatalogQueries";
import { useProductCategories } from "@/features/products/hooks/useCategoryQueries";
import { useExternalCategories, useCategoryMappings } from "@/features/integrations/hooks/useMarketplaceQueries";
import { useFetchExternalCategoriesMutation, useSaveMappingsMutation } from "@/features/integrations/hooks/useMarketplaceMutations";

type BaseCategoryMapperProps = {
  connectionId: string;
  connectionName: string;
};

export function BaseCategoryMapper({ connectionId, connectionName }: BaseCategoryMapperProps): React.JSX.Element {
  const { toast } = useToast();

  // Queries
  const catalogsQuery = useCatalogs();
  const catalogs = useMemo(() => catalogsQuery.data ?? [], [catalogsQuery.data]);
  const catalogsLoading = catalogsQuery.isLoading;

  const [selectedCatalogId, setSelectedCatalogId] = useState<string | null>(null);
  const hasInitializedCatalog = useRef(false);

  // Auto-select default catalog
  useEffect(() => {
    let timer: NodeJS.Timeout | null = null;
    if (!selectedCatalogId && catalogs.length > 0 && !hasInitializedCatalog.current) {
      const defaultCatalog = catalogs.find((c: Catalog) => c.isDefault) ?? catalogs[0];
      if (defaultCatalog) {
        timer = setTimeout(() => {
          setSelectedCatalogId(defaultCatalog.id);
          hasInitializedCatalog.current = true;
        }, 0);
      }
    }
    return (): void => {
      if (timer) clearTimeout(timer);
    };
  }, [catalogs, selectedCatalogId]);

  const internalCategoriesQuery = useProductCategories(selectedCatalogId ?? undefined);
  const internalCategories = internalCategoriesQuery.data ?? [];
  const internalCategoriesLoading = internalCategoriesQuery.isLoading;

  const externalCategoriesQuery = useExternalCategories(connectionId);
  const externalCategories = useMemo(() => externalCategoriesQuery.data ?? [], [externalCategoriesQuery.data]);
  const externalCategoriesLoading = externalCategoriesQuery.isLoading;

  const mappingsQuery = useCategoryMappings(connectionId, selectedCatalogId);
  const mappings = useMemo(() => mappingsQuery.data ?? [], [mappingsQuery.data]);
  const mappingsLoading = mappingsQuery.isLoading;

  // Mutations
  const fetchMutation = useFetchExternalCategoriesMutation();
  const saveMutation = useSaveMappingsMutation();

  const [pendingMappings, setPendingMappings] = useState<Map<string, string>>(new Map());
  const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set());
  const hasInitializedExpansion = useRef(false);

  // Initialize expansion state
  useEffect(() => {
    let timer: NodeJS.Timeout | null = null;
    if (externalCategories.length > 0 && !hasInitializedExpansion.current) {
      timer = setTimeout(() => {
        setExpandedIds((prev: Set<string>) => {
          // If we haven't initialized yet (or just reset), expand depth 0
          if (prev.size === 0) {
            return new Set(
              externalCategories
                .filter((c: ExternalCategory) => c.depth === 0)
                .map((c: ExternalCategory) => c.id)
            );
          }
          return prev;
        });
        hasInitializedExpansion.current = true;
      }, 0);
    }
    return (): void => {
      if (timer) clearTimeout(timer);
    };
  }, [externalCategories]);

  // Reset pending mappings when catalog changes
  useEffect(() => {
    setPendingMappings(new Map());
  }, [selectedCatalogId]);

  // Fetch categories from Base.com API
  const handleFetchFromBase = async (): Promise<void> => {
    try {
      const result = await fetchMutation.mutateAsync({ connectionId });
      toast(result.message, { variant: "success" });
    } catch (error: unknown) {
      console.error("Failed to fetch from Base.com:", error);
      const message = error instanceof Error ? error.message : "Failed to fetch categories";
      toast(message, { variant: "error" });
    }
  };

  // Get current mapping for an external category
  const getMappingForExternal = useCallback(
    (externalCategoryId: string): string | null => {
      // Check pending mappings first
      if (pendingMappings.has(externalCategoryId)) {
        return pendingMappings.get(externalCategoryId) ?? null;
      }
      // Check saved mappings
      const mapping = mappings.find((m: CategoryMappingWithDetails) => m.externalCategoryId === externalCategoryId);
      return mapping?.internalCategoryId ?? null;
    },
    [mappings, pendingMappings]
  );

  // Handle mapping change
  const handleMappingChange = (externalCategoryId: string, internalCategoryId: string | null): void => {
    setPendingMappings((prev: Map<string, string>) => {
      const next = new Map(prev);
      if (internalCategoryId) {
        next.set(externalCategoryId, internalCategoryId);
      } else {
        next.delete(externalCategoryId);
      }
      return next;
    });
  };

  // Save all pending mappings
  const handleSave = async (): Promise<void> => {
    if (pendingMappings.size === 0 || !selectedCatalogId) {
      toast("No changes to save", { variant: "info" });
      return;
    }

    try {
      const mappingsToSave = Array.from(pendingMappings.entries()).map(
        ([externalCategoryId, internalCategoryId]: [string, string]) => ({
          externalCategoryId,
          internalCategoryId,
        })
      );

      const result = await saveMutation.mutateAsync({
        connectionId,
        catalogId: selectedCatalogId,
        mappings: mappingsToSave,
      });

      toast(result.message, { variant: "success" });
      setPendingMappings(new Map());
    } catch (error: unknown) {
      console.error("Failed to save mappings:", error);
      const message = error instanceof Error ? error.message : "Failed to save mappings";
      toast(message, { variant: "error" });
    }
  };

  // Toggle category expansion
  const toggleExpand = (categoryId: string): void => {
    setExpandedIds((prev: Set<string>) => {
      const next = new Set(prev);
      if (next.has(categoryId)) {
        next.delete(categoryId);
      } else {
        next.add(categoryId);
      }
      return next;
    });
  };

  // Build tree structure for display
  const categoryTree = useMemo((): ExternalCategory[] => {
    const buildLevel = (parentExternalId: string | null): ExternalCategory[] => {
      return externalCategories
        .filter((c: ExternalCategory) => c.parentExternalId === parentExternalId)
        .sort((a: ExternalCategory, b: ExternalCategory) => a.name.localeCompare(b.name));
    };

    return buildLevel(null);
  }, [externalCategories]);

  // Count statistics
  const stats = useMemo((): { total: number; mapped: number; pending: number } => {
    const total = externalCategories.length;
    const mapped = externalCategories.filter((c: ExternalCategory) => getMappingForExternal(c.id) !== null).length;
    const pending = pendingMappings.size;
    return { total, mapped, pending };
  }, [externalCategories, getMappingForExternal, pendingMappings.size]);

  // Render category row with children
  const renderCategory = (category: ExternalCategory, depth: number = 0): React.JSX.Element => {
    const children = externalCategories.filter((c: ExternalCategory) => c.parentExternalId === category.externalId);
    const hasChildren = children.length > 0;
    const isExpanded = expandedIds.has(category.id);
    const currentMapping = getMappingForExternal(category.id);
    const hasPendingChange = pendingMappings.has(category.id);

    return (
      <React.Fragment key={category.id}>
        <tr className={`border-b border-border ${hasPendingChange ? "bg-yellow-500/5" : ""}`}>
          <td className="px-4 py-2">
            <div className="flex items-center" style={{ paddingLeft: `${depth * 20}px` }}>
              {hasChildren ? (
                <Button
                  onClick={(): void => toggleExpand(category.id)}
                  className="mr-2 rounded p-0.5 text-gray-400 hover:bg-muted/50 hover:text-white"
                >
                  {isExpanded ? (
                    <ChevronDown className="h-4 w-4" />
                  ) : (
                    <ChevronRight className="h-4 w-4" />
                  )}
                </Button>
              ) : (
                <span className="mr-2 w-5" />
              )}
              <span className="text-sm text-gray-200">{category.name}</span>
              {currentMapping && (
                <Check className="ml-2 h-3 w-3 text-emerald-400" />
              )}
            </div>
          </td>
          <td className="px-4 py-2">
            <select
              value={currentMapping ?? ""}
              onChange={(e: React.ChangeEvent<HTMLSelectElement>): void =>
                handleMappingChange(category.id, e.target.value || null)
              }
              className="w-full rounded border bg-gray-800 px-2 py-1 text-sm text-white"
              disabled={internalCategoriesLoading || !selectedCatalogId}
            >
              <option value="">— Not mapped —</option>
              {internalCategories.map((ic: ProductCategory) => (
                <option key={ic.id} value={ic.id}>
                  {ic.name}
                </option>
              ))}
            </select>
          </td>
        </tr>
        {hasChildren && isExpanded && (
          <React.Fragment>
            {children
              .sort((a: ExternalCategory, b: ExternalCategory) => a.name.localeCompare(b.name))
              .map((child: ExternalCategory) => renderCategory(child, depth + 1))}
          </React.Fragment>
        )}
      </React.Fragment>
    );
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-semibold text-white">
            Base.com Categories
          </h2>
          <p className="text-sm text-gray-400">
            Connection: {connectionName}
          </p>
        </div>

        <div className="flex items-center gap-3">
          <Button
            onClick={(): void => { void handleFetchFromBase(); }}
            disabled={fetchMutation.isPending}
            className="flex items-center gap-2 rounded-md border bg-gray-800 px-4 py-2 text-sm text-white hover:bg-gray-700 disabled:opacity-50"
          >
            {fetchMutation.isPending ? (
              <RefreshCw className="h-4 w-4 animate-spin" />
            ) : (
              <Download className="h-4 w-4" />
            )}
            {fetchMutation.isPending ? "Fetching..." : "Fetch Categories"}
          </Button>

          <Button
            onClick={(): void => { void handleSave(); }}
            disabled={saveMutation.isPending || pendingMappings.size === 0}
            className="flex items-center gap-2 rounded-md bg-emerald-600 px-4 py-2 text-sm font-medium text-white hover:bg-emerald-500 disabled:opacity-50"
          >
            {saveMutation.isPending ? (
              <RefreshCw className="h-4 w-4 animate-spin" />
            ) : (
              <Save className="h-4 w-4" />
            )}
            {saveMutation.isPending ? "Saving..." : `Save (${pendingMappings.size})`}
          </Button>
        </div>
      </div>

      {/* Catalog Selector */}
      <div className="flex items-center gap-4">
        <Label className="text-sm text-gray-400">Target Catalog:</Label>
        <select
          value={selectedCatalogId ?? ""}
          onChange={(e: React.ChangeEvent<HTMLSelectElement>): void => setSelectedCatalogId(e.target.value || null)}
          disabled={catalogsLoading}
          className="rounded border bg-gray-800 px-3 py-2 text-sm text-white"
        >
          {catalogsLoading && <option value="">Loading...</option>}
          {!catalogsLoading && catalogs.length === 0 && (
            <option value="">No catalogs available</option>
          )}
          {catalogs.map((catalog: Catalog) => (
            <option key={catalog.id} value={catalog.id}>
              {catalog.name}
            </option>
          ))}
        </select>

        {selectedCatalogId && (
          <span className="text-xs text-gray-500">
            {internalCategories.length} internal categories
          </span>
        )}
      </div>

      {/* Stats */}
      <div className="flex gap-6 text-sm">
        <div className="text-gray-400">
          Total: <span className="text-white">{stats.total}</span>
        </div>
        <div className="text-gray-400">
          Mapped: <span className="text-emerald-400">{stats.mapped}</span>
        </div>
        {stats.pending > 0 && (
          <div className="text-gray-400">
            Unsaved changes: <span className="text-yellow-400">{stats.pending}</span>
          </div>
        )}
      </div>

      {/* Category Table */}
      <div className="overflow-hidden rounded-md border border-border">
        <table className="w-full">
          <thead>
            <tr className="border-b border-border bg-card/50">
              <th className="px-4 py-3 text-left text-xs font-medium uppercase text-gray-400">
                External Category
              </th>
              <th className="px-4 py-3 text-left text-xs font-medium uppercase text-gray-400">
                Internal Category
              </th>
            </tr>
          </thead>
          <tbody>
            {externalCategoriesLoading || mappingsLoading ? (
              <tr>
                <td colSpan={2} className="px-4 py-8 text-center text-gray-500">
                  Loading categories...
                </td>
              </tr>
            ) : externalCategories.length === 0 ? (
              <tr>
                <td colSpan={2} className="px-4 py-8 text-center text-gray-500">
                  No external categories found. Click &quot;Fetch Categories&quot; to load from Base.com.
                </td>
              </tr>
            ) : (
              categoryTree.map((category: ExternalCategory) => renderCategory(category, 0))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

import { useQuery, useMutation, useQueryClient, type UseQueryResult, type UseMutationResult } from "@tanstack/react-query";
import * as api from "../api";
import type { CurrencyOption, CountryOption, Language } from "../../../shared/types/internationalization";

export const internationalizationKeys = {
  all: ["internationalization"] as const,
  currencies: () => [...internationalizationKeys.all, "currencies"] as const,
  countries: () => [...internationalizationKeys.all, "countries"] as const,
  languages: () => [...internationalizationKeys.all, "languages"] as const,
};

export function useCurrencies(): UseQueryResult<CurrencyOption[], Error> {
  return useQuery({
    queryKey: internationalizationKeys.currencies(),
    queryFn: async (): Promise<CurrencyOption[]> => (await api.getCurrencies()) as CurrencyOption[],
  });
}

export function useCountries(): UseQueryResult<CountryOption[], Error> {
  return useQuery({
    queryKey: internationalizationKeys.countries(),
    queryFn: async (): Promise<CountryOption[]> => (await api.getCountries()) as CountryOption[],
  });
}

export function useLanguages(): UseQueryResult<Language[], Error> {
  return useQuery({
    queryKey: internationalizationKeys.languages(),
    queryFn: async (): Promise<Language[]> => (await api.getLanguages()) as Language[],
  });
}

export function useDeleteCurrencyMutation(): UseMutationResult<void, Error, string> {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: (id: string) => api.deleteCurrency(id),
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: internationalizationKeys.currencies() });
    },
  });
}

export function useDeleteCountryMutation(): UseMutationResult<void, Error, string> {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: (id: string) => api.deleteCountry(id),
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: internationalizationKeys.countries() });
    },
  });
}

export function useDeleteLanguageMutation(): UseMutationResult<void, Error, string> {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: (id: string) => api.deleteLanguage(id),
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: internationalizationKeys.languages() });
    },
  });
}

export function useSaveCurrencyMutation(): UseMutationResult<CurrencyOption, Error, { id?: string; data: Partial<CurrencyOption> }> {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async ({ id, data }: { id?: string; data: Partial<CurrencyOption> }): Promise<CurrencyOption> => 
      (await api.saveCurrency(id, data)) as CurrencyOption,
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: internationalizationKeys.currencies() });
    },
  });
}

export function useSaveCountryMutation(): UseMutationResult<CountryOption, Error, { id?: string; data: Partial<CountryOption> & { currencyIds?: string[] } }> {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async ({ id, data }: { id?: string; data: Partial<CountryOption> & { currencyIds?: string[] } }): Promise<CountryOption> => 
      (await api.saveCountry(id, data)) as CountryOption,
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: internationalizationKeys.countries() });
    },
  });
}

export function useSaveLanguageMutation(): UseMutationResult<Language, Error, { id?: string; data: Partial<Language> & { countryIds?: string[] } }> {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async ({ id, data }: { id?: string; data: Partial<Language> & { countryIds?: string[] } }): Promise<Language> => 
      (await api.saveLanguage(id, data)) as Language,
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: internationalizationKeys.languages() });
    },
  });
}

"use client";

import { Button, Input, Label, Textarea, Tabs, TabsList, TabsTrigger, TabsContent, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, useToast } from "@/shared/ui";
import { useState, useEffect } from "react";
import { useFormContext } from "react-hook-form";
import { useProductFormContext } from "@/features/products/context/ProductFormContext";
import { useQueryClient } from "@tanstack/react-query";






import { logger } from "@/shared/utils/logger";
import { cn } from "@/shared/utils";
import { ProductFormData } from "@/features/products/types";
import type { ProductAiJob } from "@/shared/types/jobs";
import type {
  AiNode,
  PathConfig,
  PathMeta,
  PathDebugSnapshot,
  PathDebugEntry,
  Edge,
  RuntimeState,
} from "@/shared/types/ai-paths";
import {
  evaluateGraph,
} from "@/features/ai-paths/lib/core/runtime/engine";
import {
  PATH_CONFIG_PREFIX,
  PATH_DEBUG_PREFIX,
  PATH_INDEX_KEY,
  TRIGGER_EVENTS,
} from "@/features/ai-paths/lib/core/constants";
import {
  createDefaultPathConfig,
} from "@/features/ai-paths/lib/core/utils/factory";
import {
  sanitizeEdges,
} from "@/features/ai-paths/lib/core/utils/graph";

const normalizeNodes = (nodes: AiNode[]): AiNode[] => {
  return nodes.map((node: AiNode) => ({
    ...node,
    id: (node.id as string) || `node-${Math.random().toString(36).substr(2, 9)}`,
    title: (node.title as string) || (node.type as string) || "Untitled Node",
  }));
};

export default function ProductFormGeneral(): React.JSX.Element {
  const queryClient = useQueryClient();
  const safeJsonStringify = (value: unknown): string => {
    const seen = new WeakSet();
    const replacer = (_key: string, val: unknown): unknown => {
      if (typeof val === "bigint") return val.toString();
      if (val instanceof Date) return val.toISOString();
      if (val instanceof Set) return Array.from(val.values());
      if (val instanceof Map) return Object.fromEntries(val.entries());
      if (typeof val === "function" || typeof val === "symbol") return undefined;
      if (val && typeof val === "object") {
        if (seen.has(val)) return undefined;
        seen.add(val);
      }
      return val;
    };
    try {
      return JSON.stringify(value, replacer);
    } catch {
      return "";
    }
  };
  const {
    filteredLanguages,
    errors,
    generationError,
    setGenerationError,
    product,
    imageSlots,
    selectedCatalogIds,
  } = useProductFormContext();

  const { register, getValues, setValue, watch } = useFormContext<ProductFormData>();
  const { toast } = useToast();

  const [generating, setGenerating] = useState<boolean>(false);
  const [translating, setTranslating] = useState<boolean>(false);
  const [identifierType, setIdentifierType] = useState<"ean" | "gtin" | "asin">("ean");
  const allValues = watch();
  const hasCatalogs = selectedCatalogIds.length > 0;
  const languagesReady = filteredLanguages.length > 0;

  useEffect((): void => {
    const vals = getValues();
    if (vals.asin) {
      setIdentifierType("asin");
    } else if (vals.gtin) {
      setIdentifierType("gtin");
    }
  }, [getValues]);

  const handleGenerateDescription = async (): Promise<void> => {
    logger.log("Generating description...");
    setGenerating(true);
    setGenerationError(null);
    const productData = getValues();
    const imageUrls = imageSlots
      .filter((slot: import("@/features/products/types/products-ui").ProductImageSlot | null): slot is NonNullable<import("@/features/products/types/products-ui").ProductImageSlot> => slot !== null && 'previewUrl' in slot)
      .map((slot: NonNullable<import("@/features/products/types/products-ui").ProductImageSlot>) => slot.previewUrl);

    try {
      if (product?.id) {
        const enqueueRes = await fetch("/api/products/ai-jobs/enqueue", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            productId: product.id,
            type: "description_generation",
            payload: {} 
          }),
        });

        const enqueueData = (await enqueueRes.json()) as { error?: string; jobId?: string };
        if (!enqueueRes.ok) throw new Error(enqueueData.error || "Failed to enqueue generation job.");
        const jobId = enqueueData.jobId;

        let completed = false;
        let attempts = 0;
        while (!completed && attempts < 30) {
          await new Promise((r: (value: void | PromiseLike<void>) => void) => setTimeout(r, 2000));
          const statusRes = await fetch(`/api/products/ai-jobs/${jobId}`);
          if (!statusRes.ok) break;
          const { job } = (await statusRes.json()) as { job: ProductAiJob };

          if (job.status === "completed") {
            const description = job.result?.description;
            if (typeof description === "string") {
              setValue("description_en", description);
            }
            completed = true;
          } else if (job.status === "failed") {
            throw new Error(job.errorMessage || "Generation failed.");
          }
          attempts++;
        }
        if (!completed) throw new Error("Generation is taking longer than expected. Check the AI Jobs page.");
      } else {
        const res = await fetch("/api/generate-description", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ productData, imageUrls }),
        });
        if (!res.ok) {
          const payload = (await res.json()) as { error?: string; errorId?: string };
          throw new Error(payload?.error || "Failed to generate description");
        }
        const { description } = (await res.json()) as { description: string };
        setValue("description_en", description);
      }
    } catch (error) {
      logger.error("Failed to generate description:", error);
      setGenerationError(error instanceof Error ? error.message : "Failed to generate description.");
    } finally {
      setGenerating(false);
    }
  };

  const buildTriggerContext = (
    triggerNode: AiNode,
    triggerEvent: string,
    event?: React.MouseEvent<HTMLButtonElement>,
    pathInfo?: { id?: string; name?: string }
  ): Record<string, unknown> => {
    const timestamp = new Date().toISOString();
    const nativeEvent = event?.nativeEvent;
    const pointer = nativeEvent
      ? {
          clientX: nativeEvent.clientX,
          clientY: nativeEvent.clientY,
          pageX: nativeEvent.pageX,
          pageY: nativeEvent.pageY,
          screenX: nativeEvent.screenX,
          screenY: nativeEvent.screenY,
          offsetX: "offsetX" in nativeEvent ? (nativeEvent as unknown as { offsetX: number }).offsetX : undefined,
          offsetY: "offsetY" in nativeEvent ? (nativeEvent as unknown as { offsetY: number }).offsetY : undefined,
          button: nativeEvent.button,
          buttons: nativeEvent.buttons,
          altKey: nativeEvent.altKey,
          ctrlKey: nativeEvent.ctrlKey,
          shiftKey: nativeEvent.shiftKey,
          metaKey: nativeEvent.metaKey,
        }
      : undefined;
    const location =
      typeof window !== "undefined"
        ? {
            href: window.location.href,
            origin: window.location.origin,
            pathname: window.location.pathname,
            search: window.location.search,
            hash: window.location.hash,
            referrer: document.referrer || undefined,
          }
        : {};
    const ui =
      typeof window !== "undefined"
        ? {
            viewport: {
              width: window.innerWidth,
              height: window.innerHeight,
              devicePixelRatio: window.devicePixelRatio,
            },
            screen: {
              width: window.screen?.width,
              height: window.screen?.height,
              availWidth: window.screen?.availWidth,
              availHeight: window.screen?.availHeight,
            },
            userAgent: navigator.userAgent,
            platform: navigator.platform,
            language: navigator.language,
            languages: navigator.languages,
            timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone,
            documentTitle: document.title,
            visibilityState: document.visibilityState,
            scroll: {
              x: window.scrollX,
              y: window.scrollY,
            },
          }
        : {};
    return {
      timestamp,
      location,
      ui,
      user: null,
      event: {
        id: triggerEvent,
        nodeId: triggerNode.id as string,
        nodeTitle: triggerNode.title as string,
        type: event?.type,
        pointer,
      },
      source: {
        pathId: pathInfo?.id,
        pathName: pathInfo?.name ?? "Product Panel",
        tab: "product",
      },
      extras: {
        triggerLabel: "Path Generate Description",
      },
      entityId: product?.id,
      productId: product?.id,
      entityType: "product",
    };
  };

  const handlePathGenerateDescription = async (
    event?: React.MouseEvent<HTMLButtonElement>
  ): Promise<void> => {
    if (!product?.id) {
      toast("Save the product before running a path trigger.", {
        variant: "error",
      });
      return;
    }
    try {
      const prefsRes = await fetch("/api/user/preferences", { cache: "no-store" });
      if (!prefsRes.ok) {
        throw new Error("Failed to load AI Paths preferences.");
      }
      const prefs = (await prefsRes.json()) as {
        aiPathsPathConfigs?: Record<string, PathConfig> | string | null;
        aiPathsPathIndex?: Array<{ id?: string }> | null;
      };
      let configs: Record<string, PathConfig> = {};
      let settingsPathOrder: string[] = [];
      if (typeof prefs.aiPathsPathConfigs === "string") {
        try {
          const parsed = JSON.parse(prefs.aiPathsPathConfigs) as Record<string, PathConfig>;
          configs = parsed && typeof parsed === "object" ? parsed : {};
        } catch {
          configs = {};
        }
      } else if (prefs.aiPathsPathConfigs && typeof prefs.aiPathsPathConfigs === "object") {
        configs = prefs.aiPathsPathConfigs;
      }
      if (!configs || Object.keys(configs).length === 0) {
        try {
          const settingsRes = await fetch("/api/settings", { cache: "no-store" });
          if (settingsRes.ok) {
            const data = (await settingsRes.json()) as Array<{ key: string; value: string }>;
            const map = new Map<string, string>(data.map((item: { key: string; value: string }) => [item.key, item.value]));
            const indexRaw = map.get(PATH_INDEX_KEY);
            if (indexRaw) {
              try {
                const parsedIndex = JSON.parse(indexRaw) as PathMeta[];
                if (Array.isArray(parsedIndex)) {
                  settingsPathOrder = parsedIndex
                    .map((meta: PathMeta) => meta?.id as string)
                    .filter((id: string | undefined): id is string => typeof id === "string" && id.length > 0);
                  parsedIndex.forEach((meta: PathMeta) => {
                    if (!meta?.id) return;
                    const configRaw = map.get(`${PATH_CONFIG_PREFIX}${meta.id as string}`);
                    if (!configRaw) {
                      configs[meta.id as string] = createDefaultPathConfig(meta.id as string);
                      return;
                    }
                    try {
                      const parsedConfig = JSON.parse(configRaw) as PathConfig;
                      configs[meta.id as string] = {
                        ...createDefaultPathConfig(meta.id as string),
                        ...parsedConfig,
                        id: meta.id as string,
                        name: (parsedConfig?.name as string) || (meta.name as string) || `Path ${meta.id as string}`,
                      };
                    } catch {
                      configs[meta.id as string] = createDefaultPathConfig(meta.id as string);
                    }
                  });
                }
              } catch {
                settingsPathOrder = [];
              }
            }
            if (Object.keys(configs).length === 0) {
              const legacyRaw =
                map.get(`${PATH_CONFIG_PREFIX}default`) ?? map.get("ai_paths_config");
              if (legacyRaw) {
                try {
                  const parsedConfig = JSON.parse(legacyRaw) as PathConfig;
                  const fallback = createDefaultPathConfig((parsedConfig.id as string) ?? "default");
                  configs[fallback.id] = {
                    ...fallback,
                    ...parsedConfig,
                    id: (parsedConfig.id as string) ?? fallback.id,
                    name: (parsedConfig.name as string) || fallback.name,
                  };
                } catch {
                  const fallback = createDefaultPathConfig("default");
                  configs[fallback.id] = fallback;
                }
              }
            }
          }
        } catch {
          // If settings fallback fails, keep configs empty.
        }
      }
      const configsList: PathConfig[] = Object.values(configs);
      const pathOrder: string[] = Array.isArray(prefs.aiPathsPathIndex)
        ? prefs.aiPathsPathIndex
            .map((item: { id?: string }) => item?.id)
            .filter((id: string | undefined): id is string => typeof id === "string" && id.length > 0)
        : settingsPathOrder;
      const orderedConfigs: PathConfig[] = pathOrder.length
        ? pathOrder
            .map((id: string) => configs[id])
            .filter((config: PathConfig | undefined): config is PathConfig => Boolean(config))
        : configsList;
      const triggerEvent = (TRIGGER_EVENTS[0]?.id as string) ?? "path_generate_description";
      const triggerCandidates: PathConfig[] = orderedConfigs.filter((config: PathConfig) =>
        Array.isArray(config?.nodes)
          ? (config.nodes as AiNode[]).some(
              (node: AiNode) =>
                (node.type as string) === "trigger" &&
                ((node.config as { trigger?: { event?: string } })?.trigger?.event ?? triggerEvent) === triggerEvent
            )
          : false
      );
      const selectedConfig: PathConfig | undefined = triggerCandidates[0] ?? orderedConfigs[0];
      if (!selectedConfig) {
        toast(
          "No AI Path found. Configure a path with the Path Generate Description trigger.",
          { variant: "error" }
        );
        return;
      }
      toast(`Running AI Path: ${selectedConfig.name}`, { variant: "success" });
      const nodes: AiNode[] = normalizeNodes(
        Array.isArray(selectedConfig.nodes) ? (selectedConfig.nodes as AiNode[]) : []
      );
      const edges: Edge[] = sanitizeEdges(
        nodes,
        Array.isArray(selectedConfig.edges) ? (selectedConfig.edges as Edge[]) : []
      );
      const triggerNodes: AiNode[] = nodes.filter(
        (node: AiNode) =>
          (node.type as string) === "trigger" &&
          ((node.config as { trigger?: { event?: string } })?.trigger?.event ?? triggerEvent) === triggerEvent
      );
      const triggerNode: AiNode | undefined =
        triggerNodes.find((node: AiNode) => edges.some((edge: Edge) => (edge.from as string) === (node.id as string))) ??
        triggerNodes.find((node: AiNode) =>
          edges.some((edge: Edge) => (edge.from as string) === (node.id as string) || (edge.to as string) === (node.id as string))
        ) ??
        triggerNodes[0] ??
        nodes.find((node: AiNode) => (node.type as string) === "trigger");
      if (!triggerNode) {
        toast("No trigger node found in the selected path.", { variant: "error" });
        return;
      }
      const triggerContext: Record<string, unknown> = buildTriggerContext(triggerNode, triggerEvent, event, {
        id: selectedConfig.id as string,
        name: selectedConfig.name as string,
      });
      const runAt = new Date().toISOString();
      const runtimeState: RuntimeState = await evaluateGraph({
        nodes,
        edges,
        activePathId: (selectedConfig.id as string) ?? "path",
        activePathName: (selectedConfig.name as string) ?? undefined,
        triggerNodeId: triggerNode.id as string,
        triggerEvent,
        triggerContext,
        deferPoll: false,
        fetchEntityByType: async (entityType: string, entityId: string): Promise<Record<string, unknown> | null> => {
          if (entityType !== "product") return null;
          const res = await fetch(`/api/products/${encodeURIComponent(entityId)}`, {
            cache: "no-store",
          });
          if (!res.ok) return null;
          return (await res.json()) as Record<string, unknown>;
        },
        reportAiPathsError: (error: unknown, meta?: Record<string, unknown>, summary?: string): void => {
          logger.error(summary ?? "AI Paths trigger failed", error, meta);
        },
        toast,
      });
      void queryClient.invalidateQueries({ queryKey: ["products"] });
      void queryClient.invalidateQueries({ queryKey: ["products-count"] });
      try {
        const updatedConfig: PathConfig = {
          ...selectedConfig,
          nodes,
          edges,
          runtimeState,
          lastRunAt: runAt,
          updatedAt: runAt,
        };
        const debugEntries: PathDebugEntry[] = nodes
          .filter((node: AiNode) => (node.type as string) === "database")
          .map((node: AiNode): PathDebugEntry | null => {
            const output = (runtimeState.outputs as Record<string, unknown>)[(node.id as string)] as
              | { debugPayload?: unknown }
              | undefined;
            const debugPayload = output?.debugPayload;
            if (debugPayload === undefined || debugPayload === null) return null;
            return {
              nodeId: node.id as string,
              title: node.title as string,
              debug: debugPayload,
            };
          })
          .filter((entry: PathDebugEntry | null): entry is PathDebugEntry => Boolean(entry));
        const debugSnapshot: PathDebugSnapshot | null = debugEntries.length
          ? {
              pathId: updatedConfig.id as string,
              runAt,
              entries: debugEntries,
            }
          : null;
        configs[(updatedConfig.id as string)] = updatedConfig;
        const orderedIds: string[] = pathOrder.length
          ? pathOrder
          : orderedConfigs.map((config: PathConfig) => config.id as string);
        const safeConfigs: string = safeJsonStringify(configs);
        await fetch("/api/user/preferences", {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            aiPathsPathConfigs: safeConfigs || configs,
            aiPathsActivePathId: updatedConfig.id as string,
            ...(orderedIds.length > 0 && {
              aiPathsPathIndex: orderedIds.map((id: string) => ({ id })),
            }),
          }),
        });
        try {
          const configValue = safeJsonStringify(updatedConfig);
          const indexValue = JSON.stringify(orderedIds.map((id: string) => ({ id })));
          const debugValue = debugSnapshot ? safeJsonStringify(debugSnapshot) : "";
          if (configValue) {
            await fetch("/api/settings", {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({
                key: `${PATH_CONFIG_PREFIX}${updatedConfig.id as string}`,
                value: configValue,
              }),
            });
          }
          if (debugValue) {
            await fetch("/api/settings", {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({
                key: `${PATH_DEBUG_PREFIX}${updatedConfig.id as string}`,
                value: debugValue,
              }),
            });
          }
          if (orderedIds.length > 0) {
            await fetch("/api/settings", {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({ key: PATH_INDEX_KEY, value: indexValue }),
            });
          }
        } catch (error) {
          logger.error("Failed to persist AI Paths settings snapshot", error);
        }
      } catch (error) {
        logger.error("Failed to persist AI Paths runtime state", error);
      }
    } catch (error) {
      logger.error("Failed to run AI Path trigger", error);
      toast("Failed to run AI Path trigger.", { variant: "error" });
    }
  };

  const handleTranslate = async (): Promise<void> => {
    logger.log("Translating product...");
    setTranslating(true);

    try {
      if (!product?.id) {
        throw new Error("Product must be saved before translating.");
      }

      const enqueueRes = await fetch("/api/products/ai-jobs/enqueue", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          productId: product.id,
          type: "translation",
          payload: {}
        }),
      });

      const enqueueData = (await enqueueRes.json()) as { error?: string; jobId?: string };
      if (!enqueueRes.ok) throw new Error(enqueueData.error || "Failed to enqueue translation job.");

      logger.log(`Translation job ${enqueueData.jobId} created successfully.`);

      // Show success message - user can check Jobs page for progress
      toast("Translation job created successfully. Check the AI Jobs page for progress.", {
        variant: "success"
      });

    } catch (error) {
      logger.error("Failed to translate:", error);
      toast(
        error instanceof Error ? error.message : "Failed to create translation job.",
        { variant: "error" }
      );
    } finally {
      setTranslating(false);
    }
  };

  return (
    <div className="space-y-4">
      {!hasCatalogs && (
        <div className="rounded-md border border-amber-500/40 bg-amber-500/10 px-4 py-3 text-sm text-amber-100">
          Select a catalog to edit product titles and descriptions. Language fields are based on catalog settings.
        </div>
      )}

      {hasCatalogs && !languagesReady && (
        <div className="space-y-4">
          <div className="rounded-md border border-slate-500/30 bg-slate-500/5 px-4 py-3">
            <div className="h-4 w-40 animate-pulse rounded bg-slate-500/20" />
          </div>
          <div className="rounded-md border border-slate-500/30 bg-slate-500/5 px-4 py-3">
            <div className="mb-3 flex gap-2">
              <div className="h-7 w-24 animate-pulse rounded bg-slate-500/20" />
              <div className="h-7 w-24 animate-pulse rounded bg-slate-500/20" />
              <div className="h-7 w-24 animate-pulse rounded bg-slate-500/20" />
            </div>
            <div className="h-10 w-full animate-pulse rounded bg-slate-500/20" />
          </div>
          <div className="rounded-md border border-slate-500/30 bg-slate-500/5 px-4 py-3">
            <div className="mb-3 flex gap-2">
              <div className="h-7 w-28 animate-pulse rounded bg-slate-500/20" />
              <div className="h-7 w-28 animate-pulse rounded bg-slate-500/20" />
              <div className="h-7 w-28 animate-pulse rounded bg-slate-500/20" />
            </div>
            <div className="h-24 w-full animate-pulse rounded bg-slate-500/20" />
          </div>
        </div>
      )}

      {hasCatalogs && languagesReady && (
        <>
          <Tabs defaultValue={filteredLanguages[0] ? `${filteredLanguages[0].name.toLowerCase()}-name` : "english-name"} className="mb-4">
            <TabsList>
              {filteredLanguages.map((language: { name: string; code: string }) => {
                const fieldName = `name_${language.code.toLowerCase()}` as "name_en" | "name_pl" | "name_de";
                const fieldValue = allValues[fieldName];
                return (
                  <TabsTrigger
                    key={language.code}
                    value={`${language.name.toLowerCase()}-name`}
                    className={cn(
                      !fieldValue?.trim()
                        ? "text-muted-foreground/90 data-[state=active]:text-muted-foreground/90"
                        : "text-foreground data-[state=inactive]:text-foreground font-medium"
                    )}
                  >
                    {language.name} Name
                  </TabsTrigger>
                );
              })}
            </TabsList>
            {filteredLanguages.map((language: { name: string; code: string }) => {
              const fieldName = `name_${language.code.toLowerCase()}` as "name_en" | "name_pl" | "name_de";
              return (
                <TabsContent key={language.code} value={`${language.name.toLowerCase()}-name`}>
                  <Label htmlFor={fieldName}>{language.name} Name</Label>
                  <Input
                    id={fieldName}
                    {...register(fieldName)}
                    aria-invalid={errors[fieldName] ? "true" : "false"}
                  />
                  {errors[fieldName] && (
                    <p className="text-red-500 text-sm mt-1" role="alert">
                      {errors[fieldName]?.message}
                    </p>
                  )}
                </TabsContent>
              );
            })}
          </Tabs>

          <Tabs defaultValue={filteredLanguages[0] ? `${filteredLanguages[0].name.toLowerCase()}-description` : "english-description"} className="mb-4">
            <TabsList>
              {filteredLanguages.map((language: { name: string; code: string }) => {
                const fieldName = `description_${language.code.toLowerCase()}` as "description_en" | "description_pl" | "description_de";
                const fieldValue = allValues[fieldName];
                return (
                  <TabsTrigger
                    key={language.code}
                    value={`${language.name.toLowerCase()}-description`}
                    className={cn(
                      !fieldValue?.trim()
                        ? "text-muted-foreground/90 data-[state=active]:text-muted-foreground/90"
                        : "text-foreground data-[state=inactive]:text-foreground font-medium"
                    )}
                  >
                    {language.name} Description
                  </TabsTrigger>
                );
              })}
            </TabsList>
            {filteredLanguages.map((language: { name: string; code: string }) => {
              const fieldName = `description_${language.code.toLowerCase()}` as "description_en" | "description_pl" | "description_de";
              return (
                <TabsContent key={language.code} value={`${language.name.toLowerCase()}-description`}>
                  <Label htmlFor={fieldName}>{language.name} Description</Label>
                  <Textarea
                    id={fieldName}
                    {...register(fieldName)}
                    aria-invalid={errors[fieldName] ? "true" : "false"}
                  />
                  {errors[fieldName] && (
                    <p className="text-red-500 text-sm mt-1" role="alert">
                      {errors[fieldName]?.message}
                    </p>
                  )}
                  {language.code === "EN" && (
                    <>
                      {generationError && (
                        <div className="mb-4 rounded-md border border-red-500/40 bg-red-500/10 px-4 py-3 text-sm text-red-200">
                          {generationError}
                          <Button
                            onClick={(): void => setGenerationError(null)}
                            className="ml-4 bg-transparent text-red-200 hover:bg-red-500/20"
                          >
                            Dismiss
                          </Button>
                        </div>
                      )}
                      <div className="flex gap-2 mt-2">
                        <Button
                          type="button"
                          onClick={(): void => {
                            void handleGenerateDescription();
                          }}
                          disabled={generating}
                          aria-label="Generate product description"
                          aria-disabled={generating}
                          className="border border-white/20 hover:border-white/40"
                        >
                          {generating ? "Generating..." : "Generate Description"}
                        </Button>
                        <Button
                          type="button"
                          onClick={(event: React.MouseEvent<HTMLButtonElement>): void => {
                            void handlePathGenerateDescription(event);
                          }}
                          aria-label="Generate description via AI Path"
                          className="border border-white/20 hover:border-white/40"
                        >
                          Path Generate Description
                        </Button>
                        <Button
                          type="button"
                          variant="outline"
                          onClick={(): void => {
                            void handleTranslate();
                          }}
                          disabled={translating || !product?.id}
                          aria-label="Translate product names and descriptions"
                          aria-disabled={translating || !product?.id}
                          title={!product?.id ? "Save product before translating" : "Translate to other languages"}
                        >
                          {translating ? "Translating..." : "Translate"}
                        </Button>
                      </div>
                    </>
                  )}
                </TabsContent>
              );
            })}
          </Tabs>
        </>
      )}

      <div className="mb-4 flex flex-col gap-4 md:flex-row">
        <div className="w-full md:w-1/3">
          <Label htmlFor="sku">SKU *</Label>
          <Input
            id="sku"
            {...register("sku")}
            aria-invalid={errors.sku ? "true" : "false"}
            aria-required="true"
          />
          {errors.sku && (
            <p className="text-red-500 text-sm mt-1" role="alert">
              {errors.sku.message}
            </p>
          )}
        </div>
        <div className="flex-1">
          <Label>Product Identifier</Label>
          <div className="flex gap-2">
            <Select
              value={identifierType}
              onValueChange={(value: string): void =>
                setIdentifierType(value as "ean" | "gtin" | "asin")
              }
            >
              <SelectTrigger className="w-[100px]">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="ean">EAN</SelectItem>
                <SelectItem value="gtin">GTIN</SelectItem>
                <SelectItem value="asin">ASIN</SelectItem>
              </SelectContent>
            </Select>
            <Input
              id={identifierType}
              {...register(identifierType)}
              placeholder={`Enter ${identifierType.toUpperCase()}`}
            />
          </div>
        </div>
      </div>

      <div className="mb-4 grid grid-cols-2 gap-4 md:grid-cols-4">
        <div className="space-y-1">
          <Label htmlFor="weight">Weight</Label>
          <div className="relative max-w-[160px]">
            <Input
              id="weight"
              type="number"
              className="pr-10"
              {...register("weight", { valueAsNumber: true })}
              aria-invalid={errors.weight ? "true" : "false"}
            />
            <span className="pointer-events-none absolute right-3 top-1/2 -translate-y-1/2 text-xs text-gray-500">
              kg
            </span>
          </div>
          {errors.weight && (
            <p className="text-red-500 text-sm" role="alert">
              {errors.weight.message}
            </p>
          )}
        </div>
        <div className="space-y-1">
          <Label htmlFor="sizeLength">Length</Label>
          <div className="relative max-w-[160px]">
            <Input
              id="sizeLength"
              type="number"
              className="pr-10"
              {...register("sizeLength", { valueAsNumber: true })}
              aria-invalid={errors.sizeLength ? "true" : "false"}
            />
            <span className="pointer-events-none absolute right-3 top-1/2 -translate-y-1/2 text-xs text-gray-500">
              cm
            </span>
          </div>
          {errors.sizeLength && (
            <p className="text-red-500 text-sm" role="alert">
              {errors.sizeLength.message}
            </p>
          )}
        </div>
        <div className="space-y-1">
          <Label htmlFor="sizeWidth">Width</Label>
          <div className="relative max-w-[160px]">
            <Input
              id="sizeWidth"
              type="number"
              className="pr-10"
              {...register("sizeWidth", { valueAsNumber: true })}
              aria-invalid={errors.sizeWidth ? "true" : "false"}
            />
            <span className="pointer-events-none absolute right-3 top-1/2 -translate-y-1/2 text-xs text-gray-500">
              cm
            </span>
          </div>
          {errors.sizeWidth && (
            <p className="text-red-500 text-sm" role="alert">
              {errors.sizeWidth.message}
            </p>
          )}
        </div>
        <div className="space-y-1">
          <Label htmlFor="length">Height</Label>
          <div className="relative max-w-[160px]">
            <Input
              id="length"
              type="number"
              className="pr-10"
              {...register("length", { valueAsNumber: true })}
              aria-invalid={errors.length ? "true" : "false"}
            />
            <span className="pointer-events-none absolute right-3 top-1/2 -translate-y-1/2 text-xs text-gray-500">
              cm
            </span>
          </div>
          {errors.length && (
            <p className="text-red-500 text-sm" role="alert">
              {errors.length.message}
            </p>
          )}
        </div>
      </div>
    </div>
  );
}

